#ifndef GEMM_N28672_K4096_KERNEL_H
#define GEMM_N28672_K4096_KERNEL_H

#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <stdint.h>

#define GEMM_N_CONST 28672
#define GEMM_K_CONST 4096

// C[M,N] = A[M,K] * B[N,K]^T
// A: [M,K] fp16 row-major
// B: [N,K] fp16 row-major
// C: [M,N] fp16 row-major
void gemm_n28672_k4096_launch(const half* A, const half* B, half* C, int M, cudaStream_t stream);

#endif // GEMM_N28672_K4096_KERNEL_H

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <mma.h>

using namespace nvcuda;

// WMMA tile
static constexpr int WMMA_M = 16;
static constexpr int WMMA_N = 16;
static constexpr int WMMA_K = 16;

static constexpr int WARPS_PER_BLOCK = 4; // 128 threads

// Store accumulator fragment (float) into fp16 global memory.
// WMMA does not support store_matrix_sync to half* for float accumulators on this path;
// it supports store to float* for float accumulators. So store to float shared memory,
// then convert to half with bounds checks.
__global__ void gemm_wmma_16x16x16_kernel(const half* __restrict__ A,
                                         const half* __restrict__ B,
                                         half* __restrict__ C,
                                         int M) {
  const int warp_id = (int)threadIdx.y; // 0..WARPS_PER_BLOCK-1
  const int lane_id = (int)threadIdx.x; // 0..31

  const int tile_n = (int)blockIdx.x * WARPS_PER_BLOCK + warp_id;
  const int tile_m = (int)blockIdx.y;

  const int m0 = tile_m * WMMA_M;
  const int n0 = tile_n * WMMA_N;

  if (n0 >= GEMM_N_CONST || m0 >= M) return;

  wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> acc;
  wmma::fill_fragment(acc, 0.0f);

  // Full-tile fast path (no M tail): accumulate in registers, store via float shared then to half.
  if (m0 + WMMA_M <= M) {
#pragma unroll 8
    for (int k0 = 0; k0 < GEMM_K_CONST; k0 += WMMA_K) {
      wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, half, wmma::row_major> a_frag;
      wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, half, wmma::col_major> b_frag;

      const half* A_tile = A + (int64_t)m0 * GEMM_K_CONST + k0;
      const half* B_tile = B + (int64_t)n0 * GEMM_K_CONST + k0; // base at B[n0, k0]

      wmma::load_matrix_sync(a_frag, A_tile, GEMM_K_CONST);
      // Interpret B row-major [N,K] as col-major [K,N] with ld=K so (k,n) maps to B[n,k].
      wmma::load_matrix_sync(b_frag, B_tile, GEMM_K_CONST);

      wmma::mma_sync(acc, a_frag, b_frag, acc);
    }

    // Store to float shared (valid for float accumulator fragment), then convert/store to fp16.
    __shared__ float Cs_sh[WARPS_PER_BLOCK][WMMA_M * WMMA_N];
    float* Cs = &Cs_sh[warp_id][0];

    wmma::store_matrix_sync(Cs, acc, WMMA_N, wmma::mem_row_major);
    __syncwarp();

    half* C_tile = C + (int64_t)m0 * GEMM_N_CONST + n0;
    for (int idx = lane_id; idx < WMMA_M * WMMA_N; idx += 32) {
      int r = idx / WMMA_N;
      int c = idx - r * WMMA_N;
      // Full tile is valid in M; N is always in range due to n0 check + tile size (N divisible by 16 here).
      C_tile[(int64_t)r * GEMM_N_CONST + c] = __float2half_rn(Cs[idx]);
    }
    return;
  }

  // Tail in M: stage A with masking; stage B in col-major layout; store via float shared then masked write.
  __shared__ half As_sh[WARPS_PER_BLOCK][WMMA_M * WMMA_K];
  __shared__ half Bs_sh[WARPS_PER_BLOCK][WMMA_K * WMMA_N]; // will hold col-major [K,N] with ld=WMMA_K
  __shared__ float Cs_sh[WARPS_PER_BLOCK][WMMA_M * WMMA_N];

  half* As = &As_sh[warp_id][0];
  half* Bs = &Bs_sh[warp_id][0];
  float* Cs = &Cs_sh[warp_id][0];

#pragma unroll 8
  for (int k0 = 0; k0 < GEMM_K_CONST; k0 += WMMA_K) {
    // Stage A as row-major [16,16], ld=16, mask rows beyond M.
    for (int idx = lane_id; idx < WMMA_M * WMMA_K; idx += 32) {
      int r = idx / WMMA_K;
      int c = idx - r * WMMA_K;
      int gm = m0 + r;
      int gk = k0 + c;
      half v = __float2half(0.0f);
      if (gm < M) v = A[(int64_t)gm * GEMM_K_CONST + gk];
      As[idx] = v;
    }

    // Stage B into col-major [K,N] with ld=WMMA_K:
    // element (k,c) stored at Bs[c*WMMA_K + k] = B[n0+c, k0+k]
    for (int idx = lane_id; idx < WMMA_K * WMMA_N; idx += 32) {
      int c = idx / WMMA_K;     // 0..15 (n within tile)
      int k = idx - c * WMMA_K; // 0..15 (k within tile)
      int gn = n0 + c;
      int gk = k0 + k;
      // gn always in range here (N divisible by 16), but keep safe.
      half v = __float2half(0.0f);
      if (gn < GEMM_N_CONST) v = B[(int64_t)gn * GEMM_K_CONST + gk];
      Bs[idx] = v;
    }

    __syncwarp();

    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, half, wmma::row_major> a_frag;
    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, half, wmma::col_major> b_frag;

    wmma::load_matrix_sync(a_frag, As, WMMA_K);
    wmma::load_matrix_sync(b_frag, Bs, WMMA_K);
    wmma::mma_sync(acc, a_frag, b_frag, acc);

    __syncwarp();
  }

  wmma::store_matrix_sync(Cs, acc, WMMA_N, wmma::mem_row_major);
  __syncwarp();

  // Masked store for tail M.
  for (int idx = lane_id; idx < WMMA_M * WMMA_N; idx += 32) {
    int r = idx / WMMA_N;
    int c = idx - r * WMMA_N;
    int gm = m0 + r;
    int gn = n0 + c;
    if (gm < M && gn < GEMM_N_CONST) {
      C[(int64_t)gm * GEMM_N_CONST + gn] = __float2half_rn(Cs[idx]);
    }
  }
}

void gemm_n28672_k4096_launch(const half* A, const half* B, half* C, int M, cudaStream_t stream) {
  if (!A || !B || !C || M <= 0) return;

  dim3 block(32, WARPS_PER_BLOCK, 1);

  const int tiles_n = (GEMM_N_CONST + WMMA_N - 1) / WMMA_N; // 1792 exactly
  const int tiles_m = (M + WMMA_M - 1) / WMMA_M;

  dim3 grid((tiles_n + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK, tiles_m, 1);

  gemm_wmma_16x16x16_kernel<<<grid, block, 0, stream>>>(A, B, C, M);
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>

#include <cuda_runtime.h>
#include "kernel.h"

static void check_tensor_cuda_fp16_contig_2d(const torch::Tensor& t, const char* name) {
  TORCH_CHECK(t.defined(), name, " must be defined");
  TORCH_CHECK(t.device().is_cuda(), name, " must be a CUDA tensor");
  TORCH_CHECK(t.is_contiguous(), name, " must be contiguous");
  TORCH_CHECK(t.dtype() == torch::kFloat16, name, " must be float16");
  TORCH_CHECK(t.dim() == 2, name, " must be rank-2");
}

static inline void cuda_check_throw(cudaError_t err, const char* msg) {
  TORCH_CHECK(err == cudaSuccess, msg, ": ", cudaGetErrorString(err));
}

torch::Tensor run(torch::Tensor A, torch::Tensor B) {
  check_tensor_cuda_fp16_contig_2d(A, "A");
  check_tensor_cuda_fp16_contig_2d(B, "B");

  TORCH_CHECK(A.size(1) == GEMM_K_CONST, "A.size(1) must be K=4096, got ", A.size(1));
  TORCH_CHECK(B.size(0) == GEMM_N_CONST, "B.size(0) must be N=28672, got ", B.size(0));
  TORCH_CHECK(B.size(1) == GEMM_K_CONST, "B.size(1) must be K=4096, got ", B.size(1));
  TORCH_CHECK(A.device() == B.device(), "A and B must be on the same CUDA device");

  const int64_t M64 = A.size(0);
  TORCH_CHECK(M64 >= 0 && M64 <= INT32_MAX, "M out of int32 range: ", M64);
  const int M = (int)M64;

  auto C = torch::empty({M64, (int64_t)GEMM_N_CONST},
                        torch::TensorOptions().dtype(torch::kFloat16).device(A.device()));

  if (M == 0) return C;

  const half* A_ptr = reinterpret_cast<const half*>(A.data_ptr<at::Half>());
  const half* B_ptr = reinterpret_cast<const half*>(B.data_ptr<at::Half>());
  half* C_ptr = reinterpret_cast<half*>(C.data_ptr<at::Half>());

  cudaStream_t stream = at::cuda::getDefaultCUDAStream(A.device().index());

  gemm_n28672_k4096_launch(A_ptr, B_ptr, C_ptr, M, stream);

  cuda_check_throw(cudaGetLastError(), "Kernel launch failed");
  return C;
}

torch::Tensor run_kwargs(torch::Tensor A,
                         torch::Tensor B,
                         c10::optional<torch::Tensor> /*unused*/ = c10::nullopt) {
  return run(A, B);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "gemm_n28672_k4096 (CUDA)");
  m.def("run_kwargs", &run_kwargs, "gemm_n28672_k4096 (CUDA, kwargs helper)");
}
